<x-guest-layout>
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>TourEase Pro — Sign In</title>
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box;}

:root{
  --ink:     #0F1923;
  --ink2:    #1E2D3D;
  --mist:    #8B9BAA;
  --fog:     #C4CDD6;
  --paper:   #F8F6F3;
  --cream:   #FDFCFA;
  --amber:   #D4882A;
  --amber2:  #F0A83A;
  --ember:   #C0392B;
  --glow:    rgba(212,136,42,.15);
  --glass:   rgba(255,255,255,.06);
}

html,body{
  width:100vw; height:100vh;
  overflow:hidden;
  font-family:'Outfit',sans-serif;
  background:var(--ink);
}

/* ── FULL STAGE ── */
#stage{
  position:fixed; inset:0;
  display:flex;
  z-index:9999;
}

/* suppress guest layout */
body>div:not(#stage){
  display:contents !important;
  all:unset !important;
}

/* ════════════════════════════
   PHOTO SIDE
════════════════════════════ */
#photo-side{
  position:relative;
  width:55%;
  flex-shrink:0;
  overflow:hidden;
}

/* slides */
.slide{
  position:absolute; inset:0;
  background-size:cover;
  background-position:center;
  will-change:opacity,transform;
}
.s1{background-image:url('data:image/jpeg;base64,');   animation:s1 21s ease-in-out infinite;}
.s2{background-image:url('data:image/jpeg;base64,');   animation:s2 21s ease-in-out infinite;}
.s3{background-image:url('data:image/jpeg;base64,'); animation:s3 21s ease-in-out infinite;}

@keyframes s1{
  0%,32%{opacity:1;transform:scale(1.05) translateX(0);}
  36%,99%{opacity:0;transform:scale(1.09) translateX(-8px);}
  100%{opacity:1;transform:scale(1.05) translateX(0);}
}
@keyframes s2{
  0%,35%{opacity:0;}
  36%,65%{opacity:1;transform:scale(1.05) translateY(0);}
  69%,100%{opacity:0;transform:scale(1.09) translateY(-6px);}
}
@keyframes s3{
  0%,68%{opacity:0;}
  69%,96%{opacity:1;transform:scale(1.05) translateX(0);}
  100%{opacity:0;transform:scale(1.09) translateX(6px);}
}

/* multi-layered overlay for drama */
.overlay-base{
  position:absolute; inset:0;
  background:
    linear-gradient(to right, rgba(15,25,35,.1) 0%, rgba(15,25,35,0) 100%),
    linear-gradient(to top, rgba(15,25,35,.95) 0%, rgba(15,25,35,.3) 45%, rgba(15,25,35,.05) 100%);
}
.overlay-side{
  position:absolute; inset:0;
  background:linear-gradient(to right, rgba(15,25,35,0) 60%, rgba(15,25,35,.98) 100%);
}
.overlay-grain{
  position:absolute; inset:0; opacity:.04;
  background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size:180px;
}

/* photo UI chrome */
.photo-chrome{
  position:absolute; inset:0;
  display:flex; flex-direction:column;
  justify-content:space-between;
  padding:44px 48px 44px 44px;
  z-index:2;
}

.brand{
  display:flex; align-items:center; gap:10px;
  text-decoration:none;
}
.brand-mark{
  width:36px; height:36px;
  background:linear-gradient(135deg,var(--amber),var(--amber2));
  border-radius:8px;
  display:flex; align-items:center; justify-content:center;
  font-size:.9rem; color:#fff; font-weight:700;
  font-family:'Playfair Display',serif;
  box-shadow:0 4px 16px rgba(212,136,42,.4);
}
.brand-name{
  font-family:'Playfair Display',serif;
  font-size:1.3rem; font-weight:700; color:#fff;
  letter-spacing:.3px;
}
.brand-name span{
  font-style:italic; color:var(--amber2);
}

.photo-bottom{}

/* location badge */
.loc-badge{
  display:inline-flex; align-items:center; gap:8px;
  background:rgba(255,255,255,.1);
  backdrop-filter:blur(12px);
  border:1px solid rgba(255,255,255,.14);
  border-radius:100px;
  padding:7px 14px 7px 10px;
  font-size:.72rem; font-weight:600; color:rgba(255,255,255,.85);
  letter-spacing:.5px; text-transform:uppercase;
  margin-bottom:22px;
}
.loc-dot{
  width:7px; height:7px; border-radius:50%;
  background:var(--amber2);
  animation:pulse 2s ease-in-out infinite;
}
@keyframes pulse{0%,100%{opacity:1;transform:scale(1);} 50%{opacity:.5;transform:scale(.7);}}

.photo-headline{
  font-family:'Playfair Display',serif;
  font-size:clamp(2.8rem,4.2vw,4.4rem);
  font-weight:700; line-height:1.02;
  color:#fff; margin-bottom:18px;
  letter-spacing:-.5px;
}
.photo-headline em{
  font-style:italic; color:var(--amber2);
  display:block;
}

.photo-sub{
  font-size:.84rem; color:rgba(255,255,255,.52);
  line-height:1.85; max-width:340px;
  margin-bottom:38px;
}

/* stats row */
.stats{
  display:flex; gap:32px; margin-bottom:42px;
}
.stat{}
.stat-n{
  font-family:'Playfair Display',serif;
  font-size:1.6rem; font-weight:700; color:#fff;
  line-height:1;
}
.stat-n span{ color:var(--amber2); font-style:italic; }
.stat-l{
  font-size:.68rem; font-weight:600; color:rgba(255,255,255,.38);
  letter-spacing:1.5px; text-transform:uppercase; margin-top:3px;
}

/* slide indicators */
.indicators{
  display:flex; align-items:center; gap:8px;
}
.ind{
  height:3px; border-radius:2px;
  background:rgba(255,255,255,.25); cursor:pointer;
  transition:all .4s cubic-bezier(.22,.68,0,1.2);
  width:20px;
}
.ind.a{
  width:44px;
  background:linear-gradient(90deg,var(--amber),var(--amber2));
}

/* ════════════════════════════
   FORM SIDE
════════════════════════════ */
#form-side{
  flex:1;
  background:var(--ink);
  display:flex;
  align-items:center;
  justify-content:center;
  padding:48px 44px;
  overflow-y:auto;
  position:relative;
}

/* subtle background texture on form side */
#form-side::before{
  content:'';
  position:absolute; inset:0;
  background:
    radial-gradient(ellipse 60% 50% at 50% 0%, rgba(212,136,42,.06) 0%, transparent 70%),
    radial-gradient(ellipse 40% 60% at 100% 100%, rgba(30,45,61,.8) 0%, transparent 60%);
  pointer-events:none;
}

.form-wrap{
  width:100%; max-width:380px;
  position:relative; z-index:1;
  animation:rise .6s cubic-bezier(.22,.68,0,1.2) both;
}
@keyframes rise{from{opacity:0;transform:translateY(24px);} to{opacity:1;transform:translateY(0);}}

/* TABS */
.auth-tabs{
  display:flex;
  background:rgba(255,255,255,.04);
  border:1px solid rgba(255,255,255,.08);
  border-radius:10px;
  padding:4px;
  margin-bottom:36px;
  gap:4px;
}
.auth-tab{
  flex:1; padding:10px;
  font-size:.72rem; font-weight:700;
  letter-spacing:1.5px; text-transform:uppercase;
  background:none; border:none; cursor:pointer;
  font-family:'Outfit',sans-serif;
  color:var(--mist); border-radius:7px;
  transition:all .3s cubic-bezier(.22,.68,0,1.2);
}
.auth-tab.on{
  background:linear-gradient(135deg,var(--amber),var(--amber2));
  color:var(--ink);
  box-shadow:0 4px 16px rgba(212,136,42,.3);
}

/* PANELS */
.pnl{ display:none; }
.pnl.on{ display:block; animation:panelIn .35s ease both; }
@keyframes panelIn{from{opacity:0;transform:translateY(10px);} to{opacity:1;transform:translateY(0);}}

.p-hed{
  font-family:'Playfair Display',serif;
  font-size:1.85rem; font-weight:700; color:#fff;
  line-height:1.15; margin-bottom:5px;
}
.p-hed em{ color:var(--amber2); font-style:italic; }
.p-sub{
  font-size:.82rem; color:var(--mist);
  margin-bottom:28px; line-height:1.6;
}

/* DIVIDER */
.section-div{
  display:flex; align-items:center; gap:12px;
  margin-bottom:24px;
}
.section-div::before,.section-div::after{
  content:''; flex:1; height:1px;
  background:rgba(255,255,255,.07);
}
.section-div span{
  font-size:.65rem; font-weight:700;
  letter-spacing:2px; text-transform:uppercase;
  color:rgba(255,255,255,.2);
}

/* FIELDS */
.fd{ margin-bottom:14px; }
.fl{
  display:block;
  font-size:.65rem; font-weight:700;
  letter-spacing:1.8px; text-transform:uppercase;
  color:var(--fog); margin-bottom:7px;
  opacity:.7;
}
.fw{ position:relative; }
.fic{
  position:absolute; left:14px; top:50%; transform:translateY(-50%);
  color:rgba(255,255,255,.2); font-size:.82rem;
  pointer-events:none; transition:color .25s;
}
.fw:focus-within .fic{ color:var(--amber2); }
.fin{
  width:100%; padding:12px 14px 12px 40px;
  background:rgba(255,255,255,.05);
  border:1px solid rgba(255,255,255,.09);
  border-radius:8px;
  font-family:'Outfit',sans-serif; font-size:.875rem;
  color:#fff; outline:none;
  transition:border-color .25s, background .25s, box-shadow .25s;
}
.fin::placeholder{ color:rgba(255,255,255,.2); }
.fin:focus{
  background:rgba(255,255,255,.07);
  border-color:rgba(212,136,42,.5);
  box-shadow:0 0 0 3px rgba(212,136,42,.1);
}
.fin.pr{ padding-right:42px; }
.eye-btn{
  position:absolute; right:13px; top:50%; transform:translateY(-50%);
  background:none; border:none; cursor:pointer;
  color:rgba(255,255,255,.2); font-size:.82rem; padding:2px;
  transition:color .25s;
}
.eye-btn:hover{ color:var(--amber2); }

/* 2-col row */
.fd2{ display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-bottom:14px; }

/* label+forgot row */
.lbl-row{
  display:flex; justify-content:space-between; align-items:center;
  margin-bottom:7px;
}
.fgt{
  font-size:.72rem; color:var(--amber2); font-weight:500;
  text-decoration:none; opacity:.85; transition:opacity .2s;
}
.fgt:hover{ opacity:1; text-decoration:underline; }

/* REMEMBER */
.rem{
  display:flex; align-items:center; gap:8px;
  margin-bottom:22px;
}
.rem input{ accent-color:var(--amber2); cursor:pointer; }
.rem label{ font-size:.78rem; color:var(--mist); cursor:pointer; }

/* SUBMIT */
.btn-main{
  width:100%; padding:14px;
  border:none; border-radius:8px;
  background:linear-gradient(135deg, var(--amber) 0%, var(--amber2) 100%);
  color:var(--ink);
  font-family:'Outfit',sans-serif;
  font-size:.77rem; font-weight:700;
  letter-spacing:2px; text-transform:uppercase; cursor:pointer;
  display:flex; align-items:center; justify-content:center; gap:8px;
  position:relative; overflow:hidden;
  transition:transform .25s, box-shadow .25s;
  margin-bottom:20px;
  box-shadow:0 6px 24px rgba(212,136,42,.25);
}
.btn-main::after{
  content:''; position:absolute; inset:0;
  background:rgba(255,255,255,.18);
  transform:translateX(-120%) skewX(-18deg);
  transition:transform .5s;
}
.btn-main:hover::after{ transform:translateX(120%) skewX(-18deg); }
.btn-main:hover{
  transform:translateY(-3px);
  box-shadow:0 14px 36px rgba(212,136,42,.35);
}
.btn-main:active{ transform:translateY(-1px); }

/* OR */
.or-line{
  display:flex; align-items:center; gap:12px;
  font-size:.65rem; color:rgba(255,255,255,.2);
  letter-spacing:2px; text-transform:uppercase;
  margin-bottom:16px;
}
.or-line::before,.or-line::after{
  content:''; flex:1; height:1px;
  background:rgba(255,255,255,.07);
}

/* SOCIAL */
.socials{ display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-bottom:24px; }
.s-btn{
  display:flex; align-items:center; justify-content:center; gap:8px;
  padding:11px; border-radius:8px;
  border:1px solid rgba(255,255,255,.09);
  background:rgba(255,255,255,.04);
  font-size:.77rem; font-weight:600;
  font-family:'Outfit',sans-serif; color:rgba(255,255,255,.7);
  cursor:pointer; text-decoration:none;
  transition:all .25s;
}
.s-btn:hover{
  background:rgba(255,255,255,.08);
  border-color:rgba(255,255,255,.18);
  color:#fff; transform:translateY(-2px);
}
.gi{ color:#EA4335; } .fi2{ color:#4267B2; }

/* SWITCH */
.sw{
  text-align:center; font-size:.79rem; color:var(--mist);
  line-height:1.6;
}
.sw a{
  color:var(--amber2); font-weight:600;
  cursor:pointer; text-decoration:none;
  transition:opacity .2s;
}
.sw a:hover{ text-decoration:underline; }

/* PW STRENGTH */
.pwb{ display:flex; gap:5px; margin-top:7px; }
.pwb-seg{
  flex:1; height:3px; border-radius:2px;
  background:rgba(255,255,255,.1); transition:background .35s;
}
.pwb-seg.w{ background:#c0392b; }
.pwb-seg.f{ background:#e67e22; }
.pwb-seg.s{ background:#27ae60; }
.pwb-lbl{ font-size:.66rem; color:var(--mist); margin-top:4px; }

/* AGREE */
.agr{
  display:flex; align-items:flex-start; gap:9px;
  font-size:.78rem; color:var(--mist); cursor:pointer;
  margin-bottom:18px; line-height:1.55;
}
.agr input{ margin-top:3px; accent-color:var(--amber2); flex-shrink:0; }
.agr a{ color:var(--amber2); font-weight:600; }

/* ERRORS */
.ferr{ font-size:.72rem; color:#e06c75; margin-top:5px; }
.sess{
  background:rgba(39,174,96,.1); border:1px solid rgba(39,174,96,.25);
  border-radius:6px; padding:10px 13px;
  font-size:.79rem; color:#6fcf97; margin-bottom:16px;
}

/* MOBILE */
@media(max-width:820px){
  #photo-side{ display:none; }
  #form-side{ padding:36px 24px; }
}
</style>
</head>
