<script>
// TAB SWITCH
function sw(t){
  document.getElementById('pl').classList.toggle('on',t==='l');
  document.getElementById('pr').classList.toggle('on',t==='r');
  document.getElementById('tl').classList.toggle('on',t==='l');
  document.getElementById('tr').classList.toggle('on',t==='r');
}

// SLIDE DOTS
var si=0;
function setSlide(i){
  si=i;
  document.querySelectorAll('.ind').forEach(function(d,j){d.classList.toggle('a',j===i);});
}
setInterval(function(){setSlide((si+1)%3);},7000);

// PASSWORD TOGGLE
function tp(id,btn){
  var inp=document.getElementById(id);
  var show=inp.type==='password';
  inp.type=show?'text':'password';
  btn.querySelector('i').className=show?'fas fa-eye-slash':'fas fa-eye';
}

// PW STRENGTH
var rpwEl=document.getElementById('rpw');
if(rpwEl){
  rpwEl.addEventListener('input',function(){
    var v=rpwEl.value;
    var bars=['b1','b2','b3'].map(function(id){return document.getElementById(id);});
    var lbl=document.getElementById('bl');
    bars.forEach(function(b){if(b)b.className='pwb-seg';});
    if(!v){lbl.textContent='';return;}
    var s=0;
    if(v.length>=8)s++;
    if(/[A-Z]/.test(v)&&/[0-9]/.test(v))s++;
    if(/[^A-Za-z0-9]/.test(v))s++;
    var lv=Math.min(s,2);
    var cls=['w','f','s'],lb=['Weak password','Fair password','Strong password'],co=['#c0392b','#e67e22','#27ae60'];
    for(var i=0;i<=lv;i++)if(bars[i])bars[i].classList.add(cls[lv]);
    lbl.textContent=lb[lv]; lbl.style.color=co[lv];
  });
}

// AUTO TAB
if(new URLSearchParams(location.search).get('tab')==='register') sw('r');
</script>

</body>
</html>
